function setField(fieldName, val) {
  try {
    const app = document.getElementById('vue-form-renderer');
    const vm  = app && app.__vue__;
    if (vm && vm.formData && vm.formData._root) {
      vm.$set(vm.formData._root, fieldName, val);
      return;
    }
  } catch (e) {}

  const input = document.querySelector(`[name="${fieldName}"]`);
  if (input) {
    input.value = val;
    input.dispatchEvent(new Event('input', { bubbles: true }));
  }
}

