(function () {
  const MODAL_ID = 'modal_preventivo_crearCliente';
  const FOOTER_SUFFIX = '___BV_modal_footer_';

  // ⚙️ Helper genérico para setear campos en el form de PM4
  function setField(fieldName, val) {
    // Intenta setear directo en el form renderer de PM4
    try {
      const app = document.getElementById('vue-form-renderer');
      const vm = app && app.__vue__;
      if (vm && vm.formData && vm.formData._root) {
        vm.$set(vm.formData._root, fieldName, val);
        return;
      }
    } catch (e) {}

    // Fallback: si tienes un input oculto con ese name:
    const input = document.querySelector(`[name="${fieldName}"]`);
    if (input) {
      input.value = val;
      input.dispatchEvent(new Event('input', { bubbles: true }));
    }
  }

  // ⬇️ Guarda la última decisión también en window.* (útil si usarás un cálculo con return)
  function setDecision(val /* "true" | "false" */) {
    window.__crearClienteUltimaDecision = val; // <- memoria global sencilla

    // Actualiza el flag principal del crear cliente
    setField('frm_tom_cc_crear_cliente_flag', val);
  }

  function log(...args) { try { console.log('[PM4 MODAL DEBUG]', ...args); } catch (_) {} }

  function findModalFooter() {
    const id = `${MODAL_ID}${FOOTER_SUFFIX}`;
    const local = document.getElementById(id);
    const topDoc = (window.top && window.top.document) ? window.top.document : null;
    const topEl = topDoc ? topDoc.getElementById(id) : null;
    if (local) return { el: local, scope: 'local-document' };
    if (topEl) return { el: topEl, scope: 'top-document' };
    return null;
  }

  function bindFooterHandlers(footerInfo) {
    if (!footerInfo || !footerInfo.el) {
      log('No hay footer para enlazar (bindFooterHandlers)');
      return false;
