}

return total_ventas;

const frm_lista_detalle_exportaciones = this.frm_lista_detalle_exportaciones || [];

let total = 0;

for (const row of frm_lista_detalle_exportaciones) {
  if (!row) continue;
  total += row.frm_exportacion_porcentaje || 0;
}

return total;

const raw = this.frm_exportacion_porcentaje;
  if (raw == null || raw === "") return "";

  let s = String(raw).trim().replace(/\s/g, "").replace(/%/g, "");

  s = s.replace(",", ".");

  s = s.replace(/[^0-9.-]/g, "");

  const n = Number(s);
  if (!Number.isFinite(n)) return "";

  return `${n} %`;

const normalize = v => (v && typeof v === 'object') ? (v.value ?? v.content ?? '') : v;

  const v = normalize(this.frm_cot_moneda);

  if (v) {
    window._last_moneda_dup_exportaciones = v;
    return v;            
  }

  return window._last_moneda_dup_exportaciones ?? '';

const cantidad_frm_lista_detalle_exportaciones = 6;
const lista = Array.isArray(this.frm_lista_detalle_exportaciones)
      ? this.frm_lista_detalle_exportaciones
      : [];

    return lista.length >= cantidad_frm_lista_detalle_exportaciones ? "true" : "false";

const raw = this.frm_lista_detalle_exportaciones_ventas_total;
  if (raw == null || raw === "") return "";

  let s = String(raw).trim().replace(/\s/g, "").replace(/\$/g, "");

  if (s.includes(".")) {
    s = s.split(".")[0];
  } else {
    if (/,(\d{1,6})$/.test(s)) {
      s = s.replace(/,(\d{1,6})$/, "");
    }
  }

  s = s.replace(/[^\d-]/g, "");
  if (!s || s === "-") return "";

  const negative = s.startsWith("-");
  const digits = negative ? s.slice(1) : s;

  const formatted = digits.replace(/\B(?=(\d{3})+(?!\d))/g, ".");
  return negative ? `-${formatted}` : formatted;

const root = document.querySelector('[selector="list-detalle-exportaciones"]');
if (!root) return;

const table   = root.querySelector('table.record-list-table-secondary');
const wrapper = root.querySelector('.data-table');

if (!table || !wrapper) return;

const updateMaxRowsState = () => {
  const rows = table.querySelectorAll('tbody tr').length;
  if (rows >= 6) {
    wrapper.classList.add('max-rows');
  } else {
    wrapper.classList.remove('max-rows');
  }
};

updateMaxRowsState();

const raw = this.frm_exportacion_ventas;
  if (raw == null || raw === "") return "";

  let s = String(raw).trim().replace(/\s/g, "").replace(/\$/g, "");

  if (s.includes(".")) {
    s = s.split(".")[0];
  } else {
    if (/,(\d{1,6})$/.test(s)) {
      s = s.replace(/,(\d{1,6})$/, "");
    }
  }

  s = s.replace(/[^\d-]/g, "");
  if (!s || s === "-") return "";

  const negative = s.startsWith("-");
  const digits = negative ? s.slice(1) : s;

  const formatted = digits.replace(/\B(?=(\d{3})+(?!\d))/g, ".");
  return negative ? `-${formatted}` : formatted;

const rows = this.frm_lista_detalle_exportaciones || [];

if (!Array.isArray(rows)) return "false";

const seen = new Set();

for (const r of rows) {
  const frm_exportacion_pais_label = (r.frm_exportacion_pais_label || "")
    .trim()
    .toLowerCase();

  if (!frm_exportacion_pais_label) continue; // ignora vacíos o null

  if (seen.has(frm_exportacion_pais_label)) return "true"; // duplicado encontrado
  seen.add(frm_exportacion_pais_label);
}

return "false";

const rows = this.frm_lista_detalle_exportaciones || [];
if (!Array.isArray(rows)) return "";

const counts = new Map();

for (const r of rows) {
  const frm_exportacion_pais_label = (r.frm_exportacion_pais_label || "")
    .trim();

  if (!frm_exportacion_pais_label) continue;

  counts.set(frm_exportacion_pais_label, (counts.get(frm_exportacion_pais_label) || 0) + 1);
}

const duplicates = [];
for (const [frm_exportacion_pais_label, n] of counts.entries()) {
  if (n > 1) duplicates.push(frm_exportacion_pais_label);
}

return duplicates.join(", "); // ejemplo: "a@x.com, b@y.com"

const lista = Array.isArray(this.frm_lista_detalle_exportaciones)
  ? this.frm_lista_detalle_exportaciones
  : [];

const totales = {
  EUR_OCC: 0,
  EUR_CE:  0,
  AME_NOR: 0,
  AME_LAT: 0,
  ASI_PAC: 0,
  AFR_MO:  0
};

lista.forEach(item => {
  if (!item) return;
  const codigo = item.frm_exportacion_region_codigo;
  const valor  = Number(item.frm_exportacion_ventas) || 0;
  if (codigo && totales.hasOwnProperty(codigo)) {
    totales[codigo] += valor;
  }
});

return totales;

