try {
  const inicio_validacion_cuw = Date.now(); // ms

  function isNonEmpty(v) {
    return v !== undefined && v !== null && String(v).trim() !== "";
  }

  function isTrueFlag(v) {
    const val = String(v || "").trim().toUpperCase();
    return val === "SI" || val === "TRUE" || val === "1";
  }

  // Por si algún select viene como objeto {name/label/nombre/...}
  function extractName(maybeObj) {
    if (!maybeObj || typeof maybeObj !== "object") return null;
    return (
      maybeObj.nombre ??
      maybeObj.name ??
      maybeObj.label ??
      maybeObj.text ??
      maybeObj.descripcion ??
      null
    );
  }

  const result = {};

  // TOMADOR: sección CREAR / sección PRINCIPAL
  const crearTomador = isTrueFlag(data.frm_tom_cc_crear_cliente_flag);

  const tom_tipo_documento =
    crearTomador && isNonEmpty(data.frm_tom_cc_tipo_documento)
      ? data.frm_tom_cc_tipo_documento
      : (data.frm_tom_tipo_documento ?? null);

  const tom_tipo_documento_nombre =
    crearTomador && isNonEmpty(data.frm_tom_cc_tipo_documento_nombre)
      ? data.frm_tom_cc_tipo_documento_nombre
      : (data.frm_tom_tipo_documento_nombre ?? null);

  const tom_num_documento =
    crearTomador && isNonEmpty(data.frm_tom_cc_num_documento)
      ? data.frm_tom_cc_num_documento
      : (data.frm_tom_num_documento ?? null);

  const tom_nombres_completos =
    crearTomador && isNonEmpty(data.frm_tom_cc_nombre_compania)
      ? data.frm_tom_cc_nombre_compania
      : (data.frm_tom_nombres_completos ?? null);

  const tom_tipo_empresa =
