      ? data.frm_tom_cc_correo_facturacion
      : (data.frm_tom_correo_facturacion ?? null);

  const tom_direccion =
    crearTomador && isNonEmpty(data.frm_tom_cc_direccion)
      ? data.frm_tom_cc_direccion
      : (data.frm_tom_direccion ?? null);

  const tom_telefono =
    crearTomador && isNonEmpty(data.frm_tom_cc_telefono)
