      : (data.frm_tom_telefono ?? null);

  const tom_actividad_asegurada =
    crearTomador && isNonEmpty(data.frm_tom_cc_actividad_comercial)
      ? data.frm_tom_cc_actividad_comercial
      : (data.frm_tom_actividad_asegurada ?? null);

  // ✅ NUEVO: Departamento / Municipio (Tomador)
  const tom_departamento =
    crearTomador && isNonEmpty(data.frm_tom_cc_departamento)
      ? data.frm_tom_cc_departamento
