  result.frm_aseg_departamento          = aseg_departamento;
  result.frm_aseg_departamento_num      = aseg_departamento_num;
  result.frm_aseg_departamento_nombre   = aseg_departamento_nombre;
  result.frm_aseg_municipio             = aseg_municipio;
  result.frm_aseg_municipio_nombre      = aseg_municipio_nombre;

  // SI EL ASEGURADO ES EL MISMO TOMADOR
  const esTomador = isTrueFlag(data.frm_tom_asegurado_es_tomador_flag);

  if (esTomador) {
    if (isNonEmpty(tom_tipo_documento))        result.frm_aseg_tipo_documento        = tom_tipo_documento;
    if (isNonEmpty(tom_tipo_documento_nombre)) result.frm_aseg_tipo_documento_nombre = tom_tipo_documento_nombre;
    if (isNonEmpty(tom_num_documento))         result.frm_aseg_num_documento         = tom_num_documento;
    if (isNonEmpty(tom_nombres_completos))     result.frm_aseg_nombres_completos     = tom_nombres_completos;
    if (isNonEmpty(tom_tipo_empresa))          result.frm_aseg_tipo_empresa          = tom_tipo_empresa;
    if (isNonEmpty(tom_fecha_constitucion))    result.frm_aseg_fecha_constitucion    = tom_fecha_constitucion;
    if (isNonEmpty(tom_correo_facturacion))    result.frm_aseg_correo_facturacion    = tom_correo_facturacion;
    if (isNonEmpty(tom_direccion))             result.frm_aseg_direccion             = tom_direccion;
    if (isNonEmpty(tom_telefono))              result.frm_aseg_telefono              = tom_telefono;
    if (isNonEmpty(tom_actividad_asegurada))   result.frm_aseg_actividad_comercial   = tom_actividad_asegurada;

    if (isNonEmpty(tom_nombre))   result.frm_aseg_nombre   = tom_nombre;
    if (isNonEmpty(tom_apellido)) result.frm_aseg_apellido = tom_apellido;

    // ✅ NUEVO: copiar también ubicación
    if (isNonEmpty(tom_departamento))        result.frm_aseg_departamento        = tom_departamento;
    if (isNonEmpty(tom_departamento_num))    result.frm_aseg_departamento_num    = tom_departamento_num;
    if (isNonEmpty(tom_departamento_nombre)) result.frm_aseg_departamento_nombre = tom_departamento_nombre;
    if (isNonEmpty(tom_municipio))           result.frm_aseg_municipio           = tom_municipio;
    if (isNonEmpty(tom_municipio_nombre))    result.frm_aseg_municipio_nombre    = tom_municipio_nombre;
  }

  // ⏱ tiempo en segundos
  const fin_validacion_cuw = Date.now();
  result.tiempo_validacion_cuw = (fin_validacion_cuw - inicio_validacion_cuw) / 1000;

  return result;

} catch (e) {
  return {};
}
